import { Controller, Get, Param, NotFoundException, UseGuards } from '@nestjs/common';
import { AuthGuard } from '../guards/auth.guard';
import { UserService } from '../services/user.service';
import { ApiTags, ApiOperation, ApiResponse } from '@nestjs/swagger';

@ApiTags('profile')
@Controller('profile')
@UseGuards(AuthGuard)
export class ProfileController {
  constructor(private readonly userService: UserService) {}

  @Get(':userId')
  @ApiOperation({ summary: 'Get user profile with email preferences' })
  @ApiResponse({ status: 200, description: 'User profile retrieved' })
  @ApiResponse({ status: 404, description: 'User not found' })
  async getProfile(@Param('userId') userId: string) {
    const result = await this.userService.getProfile(userId);

    if (!result) {
      throw new NotFoundException(`User ${userId} not found`);
    }

    return {
      id: result.data.id,
      email: result.data.email,
      name: result.data.name,
      emailPreferences: {
        marketing: result.data.preferences?.marketing ?? false,
        transactional: result.data.preferences?.transactional ?? true,
        digest: result.data.preferences?.digest ?? 'weekly',
      },
    };
  }

  @Get(':userId/avatar')
  @ApiOperation({ summary: 'Get user avatar URL' })
  async getAvatar(@Param('userId') userId: string) {
    const result = await this.userService.getProfile(userId);

    if (!result) {
      throw new NotFoundException(`User ${userId} not found`);
    }

    return {
      avatarUrl: result.data.avatarUrl ?? null,
    };
  }
}

