import { Injectable } from '@nestjs/common';
import { PlanType } from '../types/plan.type';
import { SubscriptionRepository } from '../repositories/subscription.repository';
import { AnalyticsService } from '../services/analytics.service';
import { ForbiddenException } from '@nestjs/common';
import { Logger } from '../utils/logger';

@Injectable()
export class SubscriptionHandler {
  private readonly logger = new Logger(SubscriptionHandler.name);

  constructor(
    private readonly subscriptionRepo: SubscriptionRepository,
    private readonly analyticsService: AnalyticsService,
  ) {}

  async grantAnalyticsDashboardAccess(organizationId: string, userId: string): Promise<any> {
    const subscription = await this.subscriptionRepo.findActiveByOrganization(organizationId);

    if (!subscription) {
      throw new ForbiddenException('No active subscription found');
    }

    if (subscription.plan !== PlanType.PREMIUM) {
      throw new ForbiddenException(
        'Analytics dashboard is only available on the Premium plan. ' +
        `Current plan: ${subscription.plan}`,
      );
    }

    this.logger.log('Granting analytics access', { organizationId, userId, plan: subscription.plan });

    const dashboardConfig = await this.analyticsService.provisionDashboard({
      organizationId,
      userId,
      features: ['advanced-metrics', 'custom-reports', 'data-export'],
    });

    return {
      dashboardUrl: dashboardConfig.url,
      features: dashboardConfig.enabledFeatures,
      expiresAt: subscription.currentPeriodEnd,
    };
  }

  async checkFeatureAccess(organizationId: string, feature: string): Promise<boolean> {
    const subscription = await this.subscriptionRepo.findActiveByOrganization(organizationId);
    if (!subscription) return false;

    const premiumFeatures = ['analytics', 'custom-reports', 'data-export', 'api-access'];

    if (premiumFeatures.includes(feature)) {
      return subscription.plan === PlanType.PREMIUM;
    }

    return true;
  }
}

