    return {
      dashboardUrl: dashboardConfig.url,
      features: dashboardConfig.enabledFeatures,
      expiresAt: subscription.currentPeriodEnd,
    };
  }

  async checkFeatureAccess(organizationId: string, feature: string): Promise<boolean> {
    const subscription = await this.subscriptionRepo.findActiveByOrganization(organizationId);
    if (!subscription) return false;

    const premiumFeatures = ['analytics', 'custom-reports', 'data-export', 'api-access'];

    if (premiumFeatures.includes(feature)) {
      return subscription.plan === PlanType.PREMIUM;
    }

    return true;
  }
}

