import { Injectable } from '@nestjs/common';
import { ReportRepository } from '../repositories/report.repository';
import { IdGenerator } from '../utils/id-generator';
import { Logger } from '../utils/logger';

export interface CreateReportDto {
  title: string;
  organizationId: string;
  authorId: string;
  content: Record<string, unknown>;
  tags?: string[];
}

export interface Report {
  id: string;
  title: string;
  organizationId: string;
  authorId: string;
  content: Record<string, unknown>;
  tags: string[];
  createdAt: string;
  updatedAt: string;
}

@Injectable()
export class ReportService {
  private readonly logger = new Logger(ReportService.name);

  constructor(
    private readonly reportRepo: ReportRepository,
    private readonly idGenerator: IdGenerator,
  ) {}

  async createReport(dto: CreateReportDto): Promise<Report> {
    const now = new Date().toISOString();

    const report: Report = {
      id: this.idGenerator.generate(),
      title: dto.title,
      organizationId: dto.organizationId,
      authorId: dto.authorId,
      content: dto.content,
      tags: dto.tags ?? [],
      createdAt: now,
      updatedAt: now,
    };

    await this.reportRepo.insert(report);
    this.logger.log('Report created', { reportId: report.id, org: dto.organizationId });
    return report;
  }

  async getReportsByDateRange(
    organizationId: string,
    startDate: Date,
    endDate: Date,
  ): Promise<Report[]> {
    return this.reportRepo.findByDateRange(organizationId, startDate, endDate);
  }

  async updateReport(reportId: string, updates: Partial<Pick<Report, 'title' | 'content' | 'tags'>>): Promise<Report> {
    const existing = await this.reportRepo.findById(reportId);
    if (!existing) {
      throw new Error(`Report ${reportId} not found`);
    }

    const updated: Report = {
      ...existing,
      ...updates,
      updatedAt: new Date().toISOString(),
    };

    await this.reportRepo.update(updated);
    return updated;
  }
}

