### src/repositories/report.repository.ts (symbol: createdAt)
**Rationale:** The repository's findByDateRange uses MongoDB $gte/$lte operators expecting Date objects in createdAt, but createReport stores createdAt as an ISO string via toISOString(). MongoDB string comparison with Date objects produces incorrect query results.
```
import { Injectable } from '@nestjs/common';
import { DatabaseClient } from '../infrastructure/database.client';

@Injectable()
export class ReportRepository {
  constructor(private readonly db: DatabaseClient) {}

  async insert(report: any): Promise<void> {
    await this.db.collection('reports').insertOne(report);
  }

  /**
   * Finds reports within a date range.
   * IMPORTANT: createdAt field must be a Date object for
   * MongoDB comparison operators to work correctly.
   * String comparisons with $gte/$lte produce wrong results
   * because ISO string comparison is lexicographic, not
   * chronological (e.g., "2024-09-01" < "2024-10-01" works,
   * but "2024-09-30" > "2024-10-01" fails as string comparison).
   */
  async findByDateRange(orgId: string, start: Date, end: Date): Promise<any[]> {
    return this.db.collection('reports').find({
      organizationId: orgId,
      createdAt: { $gte: start, $lte: end },
    }).toArray();
  }

  async findById(id: string): Promise<any | null> {
    return this.db.collection('reports').findOne({ id });
  }

  async update(report: any): Promise<void> {
    await this.db.collection('reports').updateOne(
      { id: report.id },
      { $set: report },
    );
  }
}
