import { Injectable, Inject } from '@nestjs/common';
import { RedisClient } from '../infrastructure/redis.client';
import { TokenService } from './token.service';
import { Logger } from '../utils/logger';

interface SessionData {
  userId: string;
  token: string;
  createdAt: number;
  expiresAt: number;
  userAgent?: string;
  ipAddress?: string;
}

@Injectable()
export class SessionService {
  private readonly logger = new Logger(SessionService.name);
  private readonly SESSION_TTL = 86400; // 24 hours in seconds

  constructor(
    @Inject('REDIS_CLIENT') private readonly redis: RedisClient,
    private readonly tokenService: TokenService,
  ) {}

  async createSession(userId: string, metadata?: { userAgent?: string; ipAddress?: string }): Promise<string> {
    const token = this.tokenService.generateSessionToken();
    const now = Date.now();

    const sessionData: SessionData = {
      userId,
      token,
      createdAt: now,
      expiresAt: now + this.SESSION_TTL * 1000,
      userAgent: metadata?.userAgent,
      ipAddress: metadata?.ipAddress,
    };

    const cacheKey = `session:${userId}:${token}`;
    await this.redis.set(cacheKey, JSON.stringify(sessionData), 'EX', this.SESSION_TTL);

    this.logger.log('Session created', { userId, cacheKey });
    return token;
  }

  async invalidateSession(userId: string, token: string): Promise<void> {
    const cacheKey = `session:${userId}:${token}`;
    await this.redis.del(cacheKey);
    this.logger.log('Session invalidated', { userId });
  }

  async invalidateAllSessions(userId: string): Promise<void> {
    const pattern = `session:${userId}:*`;
    const keys = await this.redis.keys(pattern);

    if (keys.length > 0) {
      await this.redis.del(...keys);
      this.logger.log('All sessions invalidated', { userId, count: keys.length });
    }
  }
}

